mapper.select:
SELECT r.id, r.contributorId, r.title, r.description, r.copyright, r.categoryId, r.resourceTypeId, r.place, r.previewImage, r.mediaUrl, r.status, r.reviewedAt, r.createdAt, r.updatedAt, r.archivedAt, rt.typeName AS resourceType, c.categoryTopic AS categoryName FROM resource r LEFT JOIN category c ON r.categoryId = c.categoryId LEFT JOIN resourceType rt ON r.resourceTypeId = rt.resourceTypeId WHERE r.contributorId = #{contributorId}
AND r.title LIKE CONCAT('%', #{keyword}, '%')
AND r.status = #{status}
AND r.categoryId = #{categoryId}
ORDER BY r.updatedAt DESC, r.createdAt DESC
